// Types (no explicit freeing)
//===--------------------------------------------------------------------===//

//! DATE is stored as days since 1970-01-01.
//! Use the `goose_from_date` and `goose_to_date` functions to extract individual information.
typedef struct {
	int32_t days;
} goose_date;

typedef struct {
	int32_t year;
	int8_t month;
	int8_t day;
} goose_date_struct;

//! TIME is stored as microseconds since 00:00:00.
//! Use the `goose_from_time` and `goose_to_time` functions to extract individual information.
typedef struct {
	int64_t micros;
} goose_time;

typedef struct {
	int8_t hour;
	int8_t min;
	int8_t sec;
	int32_t micros;
} goose_time_struct;

//! TIME_NS is stored as nanoseconds since 00:00:00.
typedef struct {
	int64_t nanos;
} goose_time_ns;

//! TIME_TZ is stored as 40 bits for the int64_t microseconds, and 24 bits for the int32_t offset.
//! Use the `goose_from_time_tz` function to extract individual information.
typedef struct {
	uint64_t bits;
} goose_time_tz;

typedef struct {
	goose_time_struct time;
	int32_t offset;
} goose_time_tz_struct;

//! TIMESTAMP is stored as microseconds since 1970-01-01.
//! Use the `goose_from_timestamp` and `goose_to_timestamp` functions to extract individual information.
typedef struct {
	int64_t micros;
} goose_timestamp;

typedef struct {
	goose_date_struct date;
	goose_time_struct time;
} goose_timestamp_struct;

//! TIMESTAMP_S is stored as seconds since 1970-01-01.
typedef struct {
	int64_t seconds;
} goose_timestamp_s;

//! TIMESTAMP_MS is stored as milliseconds since 1970-01-01.
typedef struct {
	int64_t millis;
} goose_timestamp_ms;

//! TIMESTAMP_NS is stored as nanoseconds since 1970-01-01.
typedef struct {
	int64_t nanos;
} goose_timestamp_ns;

//! INTERVAL is stored in months, days, and micros.
typedef struct {
	int32_t months;
	int32_t days;
	int64_t micros;
} goose_interval;

//! HUGEINT is composed of a lower and upper component.
//! Its value is upper * 2^64 + lower.
//! For simplified usage, use `goose_hugeint_to_double` and `goose_double_to_hugeint`.
typedef struct {
	uint64_t lower;
	int64_t upper;
} goose_hugeint;

//! UHUGEINT is composed of a lower and upper component.
//! Its value is upper * 2^64 + lower.
//! For simplified usage, use `goose_uhugeint_to_double` and `goose_double_to_uhugeint`.
typedef struct {
	uint64_t lower;
	uint64_t upper;
} goose_uhugeint;

//! DECIMAL is composed of a width and a scale.
//! Their value is stored in a HUGEINT.
typedef struct {
	uint8_t width;
	uint8_t scale;
	goose_hugeint value;
} goose_decimal;

//! A type holding information about the query execution progress.
typedef struct {
	double percentage;
	uint64_t rows_processed;
	uint64_t total_rows_to_process;
} goose_query_progress_type;

//! The internal representation of a VARCHAR (string_t). If the VARCHAR does not
//! exceed 12 characters, then we inline it. Otherwise, we inline a four-byte prefix for faster
//! string comparisons and store a pointer to the remaining characters. This is a non-
//! owning structure, i.e., it does not have to be freed.
typedef struct {
	union {
		struct {
			uint32_t length;
			char prefix[4];
			char *ptr;
		} pointer;
		struct {
			uint32_t length;
			char inlined[12];
		} inlined;
	} value;
} goose_string_t;

//! Goose's LISTs are composed of a 'parent' vector holding metadata of each list,
//! and a child vector holding the entries of the lists.
//! The `goose_list_entry` struct contains the internal representation of a LIST metadata entry.
//! A metadata entry contains the length of the list, and its offset in the child vector.
typedef struct {
	uint64_t offset;
	uint64_t length;
} goose_list_entry;

//! A column consists of a pointer to its internal data. Don't operate on this type directly.
//! Instead, use functions such as `goose_column_data`, `goose_nullmask_data`,
//! `goose_column_type`, and `goose_column_name`.
typedef struct {
	// Deprecated, use `goose_column_data`.
	void *deprecated_data;
	// Deprecated, use `goose_nullmask_data`.
	bool *deprecated_nullmask;
	// Deprecated, use `goose_column_type`.
	goose_type deprecated_type;
	// Deprecated, use `goose_column_name`.
	char *deprecated_name;
	void *internal_data;
} goose_column;

//! 1. A standalone vector that must be destroyed, or
//! 2. A vector to a column in a data chunk that lives as long as the data chunk lives.
typedef struct _goose_vector {
	void *internal_ptr;
} * goose_vector;

//! A selection vector is a vector of indices, which usually refer to values in a vector.
//! Can be used to slice vectors, changing their length and the order of their entries.
//! Standalone selection vectors must be destroyed.
typedef struct _goose_selection_vector {
	void *internal_ptr;
} * goose_selection_vector;

//===--------------------------------------------------------------------===//
// Types (explicit freeing/destroying)
//===--------------------------------------------------------------------===//

//! Strings are composed of a `char` pointer and a size.
//! You must free `string.data` with `goose_free`.
typedef struct {
	char *data;
	idx_t size;
} goose_string;

//! BLOBs are composed of a byte pointer and a size.
//! You must free `blob.data` with `goose_free`.
typedef struct {
	void *data;
	idx_t size;
} goose_blob;

//! BITs are composed of a byte pointer and a size.
//! BIT byte data has 0 to 7 bits of padding.
//! The first byte contains the number of padding bits.
//! The padding bits of the second byte are set to 1, starting from the MSB.
//! You must free `data` with `goose_free`.
typedef struct {
	uint8_t *data;
	idx_t size;
} goose_bit;

//! BIGNUMs are composed of a byte pointer, a size, and an `is_negative` bool.
//! The absolute value of the number is stored in `data` in little endian format.
//! You must free `data` with `goose_free`.
typedef struct {
	uint8_t *data;
	idx_t size;
	bool is_negative;
} goose_bignum;

//! A query result consists of a pointer to its internal data.
