//! The possibly thread-local initialization function of the table function.
typedef void (*goose_table_function_init_t)(goose_init_info info);

//! The function to generate an output chunk during table function execution.
typedef void (*goose_table_function_t)(goose_function_info info, goose_data_chunk output);

//===--------------------------------------------------------------------===//
// Copy function types
//===--------------------------------------------------------------------===//

//! A COPY function. Must be destroyed with `goose_destroy_copy_function`.
typedef struct _goose_copy_function {
	void *internal_ptr;
} * goose_copy_function;

//! Info for the bind function of a COPY function.
typedef struct _goose_copy_function_bind_info {
	void *internal_ptr;
} * goose_copy_function_bind_info;

//! Info for the global initialization function of a COPY function.
typedef struct _goose_copy_function_global_init_info {
	void *internal_ptr;
} * goose_copy_function_global_init_info;

//! Info for the sink function of a COPY function.
typedef struct _goose_copy_function_sink_info {
	void *internal_ptr;
} * goose_copy_function_sink_info;

//! Info for the finalize function of a COPY function.
typedef struct _goose_copy_function_finalize_info {
	void *internal_ptr;
} * goose_copy_function_finalize_info;

//! The bind function to use when binding a COPY ... TO function.
typedef void (*goose_copy_function_bind_t)(goose_copy_function_bind_info info);

//! The initialization function to use when initializing a COPY ... TO function.
typedef void (*goose_copy_function_global_init_t)(goose_copy_function_global_init_info info);

//! The function to sink an input chunk into during execution of a COPY ... TO function.
typedef void (*goose_copy_function_sink_t)(goose_copy_function_sink_info info, goose_data_chunk input);

//! The function to finalize the COPY ... TO function execution.
typedef void (*goose_copy_function_finalize_t)(goose_copy_function_finalize_info info);

//===--------------------------------------------------------------------===//
// Cast types
//===--------------------------------------------------------------------===//

//! A cast function. Must be destroyed with `goose_destroy_cast_function`.
typedef struct _goose_cast_function {
	void *internal_ptr;
} * goose_cast_function;

//! The function to cast from an input vector to an output vector.
typedef bool (*goose_cast_function_t)(goose_function_info info, idx_t count, goose_vector input,
                                       goose_vector output);

//===--------------------------------------------------------------------===//
// Replacement scan types
//===--------------------------------------------------------------------===//

//! Additional replacement scan info. When setting this info, it is necessary to pass a destroy-callback function.
typedef struct _goose_replacement_scan_info {
	void *internal_ptr;
} * goose_replacement_scan_info;

//! A replacement scan function.
typedef void (*goose_replacement_callback_t)(goose_replacement_scan_info info, const char *table_name, void *data);

//===--------------------------------------------------------------------===//
// Arrow-related types
//===--------------------------------------------------------------------===//

//! Forward declare Arrow structs
//! It is important to notice that these structs are not defined by Goose but are actually Arrow external objects.
//! They're defined by the C Data Interface Arrow spec: https://arrow.apache.org/docs/format/CDataInterface.html

struct ArrowArray;

struct ArrowSchema;

//! Holds an arrow query result. Must be destroyed with `goose_destroy_arrow`.
typedef struct _goose_arrow {
	void *internal_ptr;
} * goose_arrow;

//! Holds an arrow array stream. Must be destroyed with `goose_destroy_arrow_stream`.
typedef struct _goose_arrow_stream {
	void *internal_ptr;
} * goose_arrow_stream;

//! Holds an arrow schema. Remember to release the respective ArrowSchema object.
typedef struct _goose_arrow_schema {
	void *internal_ptr;
} * goose_arrow_schema;

//! Holds an arrow converted schema (i.e., goose::ArrowTableSchema).
//! In practice, this object holds the information necessary to do proper conversion between Arrow Types and Goose
//! Types. Check goose/function/table/arrow/arrow_goose_schema.hpp for more details! Must be destroyed with
//! `goose_destroy_arrow_converted_schema`
typedef struct _goose_arrow_converted_schema {
	void *internal_ptr;
} * goose_arrow_converted_schema;

//! Holds an arrow array. Remember to release the respective ArrowSchema object.
typedef struct _goose_arrow_array {
	void *internal_ptr;
} * goose_arrow_array;

//! The arrow options used when transforming the Goose schema and datachunks into Arrow schema and arrays.
//! Used in `goose_to_arrow_schema` and `goose_data_chunk_to_arrow`
typedef struct _goose_arrow_options {
	void *internal_ptr;
} * goose_arrow_options;

//===--------------------------------------------------------------------===//
// Virtual File System Access
//===--------------------------------------------------------------------===//

typedef struct _goose_file_open_options {
	void *internal_ptr;
} * goose_file_open_options;

typedef struct _goose_file_system {
	void *internal_ptr;
} * goose_file_system;

typedef struct _goose_file_handle {
	void *internal_ptr;
} * goose_file_handle;

//===--------------------------------------------------------------------===//
// Catalog Interface
//===--------------------------------------------------------------------===//

//! A handle to a database catalog.
//! Must be destroyed with `goose_destroy_catalog`.
typedef struct _goose_catalog {
	void *internal_ptr;
} * goose_catalog;

//! A handle to a catalog entry (e.g., table, view, index, etc.).
//! Must be destroyed with `goose_destroy_catalog_entry`.
typedef struct _goose_catalog_entry {
	void *internal_ptr;
} * goose_catalog_entry;

//===--------------------------------------------------------------------===//
// Logging Types
//===--------------------------------------------------------------------===//

//! Holds a log storage object.
typedef struct _goose_log_storage {
	void *internal_ptr;
} * goose_log_storage;

//! This function is missing the logging context, which will be added later.
typedef void (*goose_logger_write_log_entry_t)(void *extra_data, goose_timestamp *timestamp, const char *level,
                                                const char *log_type, const char *log_message);

//===--------------------------------------------------------------------===//
// Goose extension access
//===--------------------------------------------------------------------===//

//! Passed to C API extension as a parameter to the entrypoint.
struct goose_extension_access {
	//! Indicate that an error has occurred.
	void (*set_error)(goose_extension_info info, const char *error);
	//! Fetch the database on which to register the extension.
	goose_database (*get_database)(goose_extension_info info);
	//! Fetch the API struct pointer.
	const void *(*get_api)(goose_extension_info info, const char *version);
};

